    "imp.whoSees" to "Tietosuoja",
    "imp.intro" to "Tämä sovellus on yhteisö: foil-sessiot jaetaan muiden kanssa. Tässä kerrotaan tarkalleen, mitkä tiedot näkyvät kenellekin.",
    "imp.publicTitle" to "🌍 Julkinen (kuka tahansa netissä, ilman kirjautumista)",
    "imp.public1" to "<b>Ladatut kuvat</b> ja <b>profiilikuvat</b>: kuvatiedostot ovat satunnaisen, arvaamattoman linkin takana. Kuka tahansa, joka tietää tämän linkin (esim. edelleen lähetettynä), voi avata kuvan ilman tiliä. EXIF-/GPS-tiedot kuvista poistetaan latauksen yhteydessä.",
    "imp.public2" to "Itse web-sovellus ja kello-sovelluksen lataus.",
    "imp.communityTitle" to "👥 Näkyy jokaiselle rekisteröityneelle (yhteisö)",
    "imp.communityIntro" to "Tilin voi luoda kuka tahansa. Kirjautuneena näkee <b>kaikilta</b> käyttäjiltä:",
    "imp.community1" to "<b>Näyttönimi</b> ja <b>profiilikuva</b> (jos asetettu; ilman näyttönimeä sessio näkyy ilman nimeä).",
    "imp.community2" to "<b>Kaikki sessiot, joissa foiling tunnistettu</b>: päivä/kellonaika, <b>spotti</b> (vesistön nimi OpenStreetMapista), <b>kartta/GPS-reitti</b> (eli <u>missä</u> foilattiin), lenkkien määrä, matka, nopeus, syke, pump-/liukuarvot ja ladatut <b>kuvat</b>.",
    "imp.community3" to "<b>Ennätykset &amp; tulostaulukot</b> (nimi, arvo, spotti, sessioiden/lenkkien/spottien määrä).",
    "imp.community4" to "<b>Tykkäykset</b> (määrä) ja „vaikuttaa epäaidolta“/„sopimaton“-äänten <b>määrä</b>.",
    "imp.communityNote" to "Sessiot <b>eivät ole anonyymejä</b> — ne on liitetty henkilöön näyttönimen kautta. Voit poistaa minkä tahansa session milloin tahansa yksitellen; vain itse <b>piilottamasi</b> sessiot eivät näy yhteisölistoissa (myös pelkät GPS-sessiot näytetään).",
    "imp.ownerTitle" to "🔒 Vain sinä itse (session omistaja)",
    "imp.owner1" to "Sessioidesi <b>raakadata</b> (yksittäiset GPS-pisteet, 25 Hz kiihtyvyys) — esim. merkitsemistä varten.",
    "imp.owner2" to "Merkinnät, rajaus, uudelleenanalysointi, kuvien lataus/poisto.",
    "imp.owner3" to "<b>Sähköpostiosoitteesi</b> ja tiliasetukset — eivät koskaan näy muille käyttäjille.",
    "imp.owner4" to "Kuka tarkalleen äänesti/tykkäsi sessiosta, ei näytetä muille käyttäjille.",
    "imp.operatorTitle" to "🛠 Vain ylläpitäjä (Jan)",
    "imp.operator1" to "Sähköpostiosoitteet, kaikki raakadata, laitelinkitykset ja tekniset palvelinlokit.",
    "imp.operator2" to "Salasanat tallennetaan vain suolattuna hashina (PBKDF2) — en näe niitäkään selkokielisenä.",
    "imp.privacyTitle" to "Tietojen poisto",
    "imp.privacyText" to "Kaikki ladatut tiedot säilytetään pysyvästi. Poistaaksesi käytä profiilisi „Poista tili“ -painiketta (web-sovellus tai iOS-/Android-sovellus) — se poistaa tilisi kaikkine sessioineen, raakadatoineen ja kuvineen lopullisesti. Tiedonsiirto on salattua (HTTPS).",
    "imp.googleTitle" to "Google-kirjautuminen (Googlen käyttäjätiedot)",
    "imp.googleIntro" to "Kun kirjaudut Google-tililläsi (Google Sign-In / OAuth), käsittelemme yksinomaan seuraavia Googlen käyttäjätietoja:",
