    "imp.google2" to "<b>Käyttö (Data Usage):</b> yksinomaan Pumpfoil-tilisi luomiseen ja kirjautumiseen sekä etunimesi näyttämiseen sovelluksessa.",
    "imp.google3" to "<b>Ei pääsyä</b> muihin Google-palveluihin tai -tietoihin (ei Google Drive, Gmail, kalenteri tms.).",
    "imp.google4" to "Näitä tietoja <b>ei luovuteta kolmansille</b>, niitä ei käytetä mainontaan eikä tekoäly-/ML-mallien kouluttamiseen.",
    "imp.googleNote" to "Google-rajapinnoista saatujen tietojen käyttö noudattaa <a href=\"https://developers.google.com/terms/api-services-user-data-policy\" target=\"_blank\" rel=\"noopener noreferrer\" class=\"text-brand-400 hover:underline\">Google API Services User Data Policya</a>, mukaan lukien Limited Use -vaatimukset.",
    "imp.appleTitle" to "Apple-kirjautuminen („Kirjaudu Applella“)",
    "imp.appleIntro" to "Kun kirjaudut Applella, käsittelemme yksinomaan seuraavia tietoja:",
    "imp.apple1" to "<b>Käyttöoikeus:</b> sähköpostiosoitteesi (tarvittaessa Applen anonymisoima „Piilota sähköpostini“ -välitysosoite), nimesi (vain kertaalleen ensimmäisen kirjautumisen yhteydessä, jos jaat sen) ja Applen käyttäjä-ID.",
    "imp.apple2" to "<b>Käyttö:</b> yksinomaan Pumpfoil-tilisi luomiseen ja kirjautumiseen.",
    "imp.apple3" to "Ei luovutusta kolmansille, ei mainontaa, ei tekoäly-/ML-koulutusta. Applen puoleisesta käsittelystä vastaa Apple oman tietosuojakäytäntönsä mukaisesti.",
    "imp.connTitle" to "Linkitetyt tilit (Polar, COROS, Suunto)",
    "imp.connIntro" to "Valinnaisesti ja vain nimenomaisella toiminnallasi voit linkittää kolmannen osapuolen tilin tuodaksesi aktiviteetteja:",
    "imp.conn1" to "Linkityksessä sinut ohjataan kyseiselle palveluntarjoajalle ja kirjaudut siellä (OAuth). Saamme pääsytokenin sekä jakamasi harjoitus-/workout-datan (mm. GPS-reitti, aika, syke).",
    "imp.conn2" to "Nämä tiedot tuodaan yksinomaan omina sessioinasi ja käsitellään kuten muutkin sessiosi.",
    "imp.conn3" to "Linkityksen voi peruuttaa milloin tahansa kohdassa „Linkitetyt tilit“ — tällöin tallennettu token poistetaan.",
    "imp.ytTitle" to "Upotetut YouTube-videot",
